# Target 'register security information' user action
# This protects the MFA registration flow itself from attackers
# (blocks registration from untrusted locations or risky IPs)
conditions = @{
    users        = @{ includeUsers = @('All') }
    applications = @{
        includeUserActions = @('urn:user:registersecurityinfo')
    }
    locations = @{
        includeLocations = @('All')
        excludeLocations = @('AllTrusted')
    }
}
grantControls = @{
    operator        = 'OR'
    builtInControls = @('block')
}

# This blocks MFA registration from outside trusted locations —
# attackers who compromise a password cannot register their own MFA method
# Users must be on corporate network or VPN to register MFA for the first time

# Policy: block high sign-in risk, require MFA + password change for medium

# Policy 1: Block if sign-in risk is High
conditions_block = @{
    users        = @{ includeUsers = @('All'); excludeGroups = @('<break-glass-oid>') }
    applications = @{ includeApplications = @('All') }
    signInRiskLevels = @('high')
}
grantControls_block = @{ operator = 'OR'; builtInControls = @('block') }

# Policy 2: Require MFA for medium sign-in risk
conditions_mfa = @{
    users            = @{ includeUsers = @('All'); excludeGroups = @('<break-glass-oid>') }
    applications     = @{ includeApplications = @('All') }
    signInRiskLevels = @('medium')
}
grantControls_mfa = @{ operator = 'OR'; builtInControls = @('mfa') }

# Policy 3: Require MFA + password change for high user risk
conditions_user_risk = @{
    users          = @{ includeUsers = @('All'); excludeGroups = @('<break-glass-oid>') }
    applications   = @{ includeApplications = @('All') }
    userRiskLevels = @('high')
}
grantControls_user_risk = @{
    operator        = 'AND'
    builtInControls = @('mfa', 'passwordChange')
}

# Device filter: apply policy ONLY to devices that are NOT compliant
# (Useful for a 'block unmanaged devices from sensitive apps' policy)
conditions = @{
    users        = @{ includeUsers = @('All') }
    applications = @{ includeApplications = @('All') }
    devices = @{
        deviceFilter = @{
            mode = 'include'
            rule = 'device.isCompliant -ne True'
        }
    }
}

# Device filter: exclude Autopilot-enrolled Windows 11 devices from MFA policy
# (They are always compliant and have hardware TPM — MFA is redundant)
conditions = @{
    users        = @{ includeUsers = @('All') }
    applications = @{ includeApplications = @('All') }
    devices = @{
        deviceFilter = @{
            mode = 'exclude'
            rule = "device.trustType -eq 'ServerAD' -and device.operatingSystem -eq 'Windows'"
        }
    }
}

# Common device filter rule attributes:
# device.isCompliant         - Intune compliance state (True/False)
# device.trustType           - AzureAD (registered), ServerAD (hybrid-joined), Workplace (registered)
# device.operatingSystem     - Windows, iOS, Android, macOS, Linux
# device.deviceCategory      - Intune device category (set per org)
# device.extensionAttribute1 - Custom attribute set via Intune or Graph

# Block all legacy authentication (all users, all apps, legacy client types)
# This is one of the most impactful security policies available
$blockLegacy = @{
    displayName = 'Block legacy authentication'
    state       = 'enabled'
    conditions  = @{
        users        = @{ includeUsers = @('All'); excludeGroups = @('<break-glass-oid>') }
        applications = @{ includeApplications = @('All') }
        clientAppTypes = @('exchangeActiveSync', 'other')
    }
    grantControls = @{
        operator        = 'OR'
        builtInControls = @('block')
    }
} | ConvertTo-Json -Depth 6

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
  -Body $blockLegacy -ContentType 'application/json'

# Before enabling: check legacy auth usage in sign-in logs
# SigninLogs | where ClientAppUsed in ('Exchange ActiveSync', 'Other clients', 'IMAP', 'POP', 'MAPI', 'SMTP', 'Authenticated SMTP')
# | summarize count() by ClientAppUsed, UserPrincipalName, AppDisplayName

# Define an authentication context
New-MgIdentityConditionalAccessAuthenticationContextClassReference -Id 'c1' \
    -DisplayName 'High-Trust Operations' \
    -Description 'Requires phishing-resistant MFA for sensitive resources' \
    -IsAvailable $true

# Assign the context to a CA policy
$conditions = @{
    AuthenticationFlows = $null
    ClientAppTypes = @('all')
    Applications = @{
        IncludeAuthenticationContextClassReferences = @('c1')
    }
}
$grantControls = @{
    Operator = 'AND'
    BuiltInControls = @('mfa')
    AuthenticationStrength = @{
        Id = '00000000-0000-0000-0000-000000000004' # Phishing-resistant MFA
    }
}
# Apply in SharePoint Online by tagging a site with c1 sensitivity label
# When user accesses the site, browser sends acr_values=c1 => CA evaluates this policy

# Microsoft Purview Insider Risk → CA integration
# Requires: Microsoft 365 E5 or E5 Compliance + Insider Risk Management license

# Step 1: Enable Adaptive Protection in Purview Insider Risk Management
# (Done in Purview portal, not PowerShell — toggles integration with CA)

# Step 2: Create CA policy targeting Insider Risk level
$body = @{
    DisplayName = 'Insider Risk - Elevated - Block Downloads'
    State = 'enabled'
    Conditions = @{
        UserRiskLevels = @()  # leave empty, Insider Risk level used separately
        InsiderRiskLevels = @('elevated')  # minor | moderate | elevated
        ClientAppTypes = @('all')
        Applications = @{
            IncludeApplications = @('Office365')
        }
    }
    SessionControls = @{
        ApplicationEnforcedRestrictions = @{ IsEnabled = $true }
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
    -Body $body -ContentType 'application/json'

# Retrieve all named locations and audit them
$locations = Get-MgIdentityConditionalAccessNamedLocation
foreach ($loc in $locations) {
    if ($loc.AdditionalProperties['@odata.type'] -eq '#microsoft.graph.ipNamedLocation') {
        $ranges = $loc.AdditionalProperties['ipRanges'] | ForEach-Object { $_.cidrAddress }
        Write-Host "IP Location: $($loc.DisplayName) — Ranges: $($ranges -join ', ')"
        Write-Host "  Trusted: $($loc.AdditionalProperties['isTrusted'])"
    } elseif ($loc.AdditionalProperties['@odata.type'] -eq '#microsoft.graph.countryNamedLocation') {
        $countries = $loc.AdditionalProperties['countriesAndRegions'] -join ', '
        Write-Host "Country Location: $($loc.DisplayName) — Countries: $countries"
        Write-Host "  Include unknowns: $($loc.AdditionalProperties['includeUnknownCountriesAndRegions'])"
    }
}

# Mark a location as Trusted (counts as compliant network for per-location exclusions)
Update-MgIdentityConditionalAccessNamedLocation -NamedLocationId '<location-id>' \
    -AdditionalProperties @{ isTrusted = $true }
